sqlMap.select:
select signUpMember as "signUpMember", belongDepart as "belongDepart", isSignUpValidate as "isSignUpValidate"
from vm_fullpollingBatchSignup where formmain_id = (select id from vm_fullpollingbatchdoc where pollingYear = #pollingYear# and util_common.getEnumValueById(yearBatch) = #yearBatch# and batchState != 4845015860421214524)
and belongDepart = (select id from org_unit where code = #kmDeptCode#)
